mapper.select:
select od.id as orderDetailId, od.manufacturer_code as manufacturerCode,od.manufacturer_name as manufacturerName, od.delivery_order_id as deliveryOrderId, od.item_no as itemNo, od.material_code as materialCode, od.material_name as materialName, od.out_material_code as outMaterialCode, od.sn_code as snCode, od.sn_name as snName, od.category_code as categoryCode,od.category_name as categoryName, od.quantity as quantity, od.identify_code as identifyCode,od.unit_id as unitId, od.unit as unit, od.out_unit as outUnit, od.stock_type as stockType, od.price as price, od.total_price as totalPrice, od.currency as currency, od.total_price_tax as totalPriceTax, od.tax_code_name as taxCodeName, od.tax_code as taxCode, od.tax_rate as taxRate, od.tax as tax, od.exchange_rate as exchangeRate, od.supply_code as supplyCode, od.supply_name as supplyName, od.customer as customer, od.customer_code as customerCode, o.tenant_id as tenantId, o.delivery_order_no as deliveryOrderNo, o.delivery_type as deliveryType, o.crm_order_no as crmOrderNo, o.out_order_no as outOrderNo, o.delivery_time as deliveryTime, o.distributor_id as distributorId, o.distributor_tenant_id as distributorTenantId, o.distributor_name as distributorName, o.distributor_type as distributorType, o.origin_system as originSystem, o.`state` as state, od.`state` as detailState from sp_delivery_order_detail od left join sp_delivery_order o on od.delivery_order_id = o.id where od.deleted = 0 and o.deleted = 0
and od.tenant_id = #{tenantId}
and od.id in
#{id}

select

from sp_delivery_order_detail
where
deleted = 0
and tenant_id = #{tenantId}
and id = #{orderDetailId}

mapper.update:
update sp_delivery_order_detail
    set state = #{state}, updator_id = #{updatorId}
where id = #{orderDetailId}
  and tenant_id = #{tenantId}

mapper.select:
